INSERT INTO `movies` VALUES (11,'Star Wars','Star Wars',1977,121,'United States of America','en','Adventure, Action, Science Fiction','Mark Hamill, Harrison Ford, Carrie Fisher, Peter Cushing, Alec Guinness','George Lucas','Princess Leia is captured and held hostage by the evil Imperial forces in their effort to take over the galactic Empire. Venturesome Luke Skywalker and dashing captain Han Solo team together with the loveable robot duo R2-D2 and C-3PO to rescue the beautiful princess and restore peace and justice in the Empire.',8.2,22151,22.276,'2026-04-14 09:09:24','XsS1yE2f-hE','/6FfCtAuVAW8XJjZ7eWeLibRLWTw.jpg'),(13,'Forrest Gump','Forrest Gump',1994,142,'United States of America','en','Comedy, Drama, Romance','Tom Hanks, Robin Wright, Gary Sinise, Sally Field, Mykelti Williamson','Robert Zemeckis','A man with a low IQ has accomplished great things in his life and been present during significant historic events—in each case, far exceeding what anyone imagined he could do. But despite all he has achieved, his one true love eludes him.',8.5,29510,24.487,'2026-04-14 09:08:18','Mj9IA9tTfio','/saHP97rTPS5eLmrLQEcANmKrsFl.jpg'),(19,'Metropolis','Metropolis',1927,148,'Germany','de','Drama, Science Fiction','Gustav Fröhlich, Brigitte Helm, Alfred Abel, Rudolf Klein-Rogge, Theodor Loos','Fritz Lang','In a futuristic city sharply divided between the rich and the poor, the son of the city\'s mastermind meets a prophet who predicts the coming of a savior to mediate their differences.',8.1,3064,4.033,'2026-04-14 09:10:24','ZAvzaOxDt2c','/kr9wXRN23zLuWJIelahas1mtnYj.jpg'),(28,'Apocalypse Now','Apocalypse Now',1979,147,'United States of America','en','Drama, War','Martin Sheen, Marlon Brando, Frederic Forrest, Albert Hall, Laurence Fishburne','Francis Ford Coppola','At the height of the Vietnam war, Captain Benjamin Willard is sent on a dangerous mission that, officially, \"does not exist, nor will it ever exist.\" His goal is to locate - and eliminate - a mysterious Green Beret Colonel named Walter Kurtz, who has been leading his personal army on illegal guerrilla missions into enemy territory.',8.3,8994,12.720,'2026-04-14 09:08:56','9l-ViOOFH-s','/gQB8Y5RCMkv2zwzFHbUJX3kAhvA.jpg'),(38,'Eternal Sunshine of the Spotless Mind','Eternal Sunshine of the Spotless Mind',2004,108,'United States of America','en','Science Fiction, Drama, Romance','Jim Carrey, Kate Winslet, Kirsten Dunst, Mark Ruffalo, Elijah Wood','Michel Gondry','Joel Barish, heartbroken that his girlfriend underwent a procedure to erase him from her memory, decides to do the same. However, as he watches his memories of her fade away, he realises that he still loves her, and may be too late to correct his mistake.',8.1,16200,27.994,'2026-04-14 09:07:29','c2e-bj6qy8Y','/5MwkWH9tYHv3mV9OdYTMR5qreIz.jpg'),(73,'American History X','American History X',1998,119,'United States of America','en','Drama','Edward Norton, Edward Furlong, Beverly D\'Angelo, Jennifer Lien, Ethan Suplee','Tony Kaye','Derek Vineyard is paroled after serving 3 years in prison for killing two African-American men. Through his brother, Danny Vineyard\'s narration, we learn that before going to prison, Derek was a skinhead and the leader of a violent white supremacist gang that committed acts of racial crime throughout L.A. and his actions greatly influenced Danny. Reformed and fresh out of prison, Derek severs contact with the gang and becomes determined to keep Danny from going down the same violent path as he did.',8.3,12461,10.967,'2026-04-14 09:08:42','el6JxnW2Tyg','/x2drgoXYZ8484lqyDj7L1CEVR4T.jpg'),(77,'Memento','Memento',2000,113,'United States of America','en','Mystery, Thriller','Guy Pearce, Carrie-Anne Moss, Joe Pantoliano, Mark Boone Junior, Russ Fega','Christopher Nolan','Leonard Shelby is tracking down the man who raped and murdered his wife. The difficulty of locating his wife\'s killer, however, is compounded by the fact that he suffers from a rare, untreatable form of short-term memory loss. Although he can recall details of life before his accident, Leonard cannot remember what happened fifteen minutes ago, where he\'s going, or why.',8.2,16082,12.918,'2026-04-14 09:09:34','Rq9eM4ZXRgs','/fKTPH2WvH8nHTXeBYBVhawtRqtR.jpg'),(98,'Gladiator','Gladiator',2000,155,'United Kingdom','en','Action, Drama, Adventure','Russell Crowe, Joaquin Phoenix, Connie Nielsen, Oliver Reed, Richard Harris','Ridley Scott','After the death of Emperor Marcus Aurelius, his devious son takes power and demotes Maximus, one of Rome\'s most capable generals who Marcus preferred. Eventually, Maximus is forced to become a gladiator and battle to the death against other men for the amusement of paying audiences.',8.2,20717,16.805,'2026-04-14 09:09:10','P5ieIbInFpg','/wN2xWp1eIwCKOD0BHTcErTBv1Uq.jpg'),(100,'Lock, Stock and Two Smoking Barrels','Lock, Stock and Two Smoking Barrels',1998,105,'United Kingdom','en','Comedy, Crime','Vinnie Jones, Jason Flemyng, Dexter Fletcher, Nick Moran, Jason Statham','Guy Ritchie','A card shark and his unwillingly-enlisted friends need to make a lot of cash quick after losing a sketchy poker match. To do this they decide to pull a heist on a small-time gang who happen to be operating out of the flat next door.',8.1,7129,2.681,'2026-04-14 09:10:14','HY7mRdQuUSw','/6pJB2t3MbQUy9m5pFIBHXLqnqNd.jpg'),(101,'Léon: The Professional','Léon',1994,111,'France','fr','Crime, Drama, Action','Jean Reno, Natalie Portman, Gary Oldman, Danny Aiello, Peter Appel','Luc Besson','Léon, the top hit man in New York, has earned a rep as an effective \"cleaner\". But when his next-door neighbors are wiped out by a loose-cannon DEA agent, he becomes the unwilling custodian of 12-year-old Mathilda. Before long, Mathilda\'s thoughts turn to revenge, and she considers following in Léon\'s footsteps.',8.3,15950,19.658,'2026-04-14 09:08:49','DD-6bmOY__g','/bxB2q91nKYp8JNzqE7t7TWBVupB.jpg'),(103,'Taxi Driver','Taxi Driver',1976,114,'United States of America','en','Crime, Drama','Robert De Niro, Jodie Foster, Cybill Shepherd, Harvey Keitel, Peter Boyle','Martin Scorsese','Suffering from insomnia, disturbed loner Travis Bickle takes a job as a New York City cabbie, haunting the streets nightly, growing increasingly detached from reality as he dreams of cleaning up the filthy city.',8.1,13316,13.623,'2026-04-14 09:09:57','zdqCqDSTVNI','/ekstpH614fwDX8DUln1a2Opz0N8.jpg'),(105,'Back to the Future','Back to the Future',1985,116,'United States of America','en','Adventure, Comedy, Science Fiction','Michael J. Fox, Christopher Lloyd, Crispin Glover, Lea Thompson, Claudia Wells','Robert Zemeckis','Eighties teenager Marty McFly is accidentally sent back in time to 1955, inadvertently disrupting his parents\' first meeting and attracting his mother\'s romantic interest. Marty must repair the damage to history by rekindling his parents\' romance and - with the help of his eccentric inventor friend Doc Brown - return to 1985.',8.3,21608,23.865,'2026-04-14 09:08:01','ez6WQ7IX72U','/vN5B5WgYscRGcQpVhHl6p9DDTP0.jpg'),(111,'Scarface','Scarface',1983,170,'United States of America','en','Action, Crime, Drama','Al Pacino, Steven Bauer, Michelle Pfeiffer, Mary Elizabeth Mastrantonio, Robert Loggia','Brian De Palma','After getting a green card in exchange for assassinating a Cuban government official, Tony Montana stakes a claim on the drug trade in Miami. Viciously murdering anyone who stands in his way, Tony eventually becomes the biggest drug lord in the state, controlling nearly all the cocaine that comes through Miami. But increased pressure from the police, wars with Colombian drug cartels and his own drug-fueled paranoia serve to fuel the flames of his eventual downfall.',8.2,12885,16.533,'2026-04-14 09:09:43','lZMIrD36MG8','/iQ5ztdjvteGeboxtmRdXEChJOHh.jpg'),(117,'The Untouchables','The Untouchables',1987,119,'United States of America','en','Crime, History, Thriller','Kevin Costner, Sean Connery, Robert De Niro, Charles Martin Smith, Andy Garcia','Brian De Palma','Elliot Ness, an ambitious prohibition agent, is determined to take down Al Capone. In order to achieve this goal, he forms a group given the nickname “The Untouchables”.',7.8,6102,44.205,'2026-03-28 06:45:24','YbzkK06MJjE','/sfMVTmd5irneaZOmQVdB8gFlId3.jpg'),(120,'The Lord of the Rings: The Fellowship of the Ring','The Lord of the Rings: The Fellowship of the Ring',2001,179,'New Zealand','en','Adventure, Fantasy, Action','Elijah Wood, Ian McKellen, Viggo Mortensen, Sean Astin, Ian Holm','Peter Jackson','Young hobbit Frodo Baggins, after inheriting a mysterious ring from his uncle Bilbo, must leave his home in order to keep it from falling into the hands of its evil creator. Along the way, a fellowship is formed to protect the ringbearer and make sure that the ring arrives at its final destination: Mt. Doom, the only place where it can be destroyed.',8.4,27310,28.879,'2026-03-27 07:50:10','_nZdmwHrcnw','/6oom5QYQ2yQTMJIbnvbkBL9cHo6.jpg'),(121,'The Lord of the Rings: The Two Towers','The Lord of the Rings: The Two Towers',2002,179,'New Zealand','en','Adventure, Fantasy, Action','Elijah Wood, Ian McKellen, Viggo Mortensen, Sean Astin, Andy Serkis','Peter Jackson','Frodo Baggins and the other members of the Fellowship continue on their sacred quest to destroy the One Ring--but on separate paths. Their destinies lie at two towers--Orthanc Tower in Isengard, where the corrupt wizard Saruman awaits, and Sauron\'s fortress at Barad-dur, deep within the dark lands of Mordor. Frodo and Sam are trekking to Mordor to destroy the One Ring of Power while Gimli, Legolas and Aragorn search for the orc-captured Merry and Pippin. All along, nefarious wizard Saruman awaits the Fellowship members at the Orthanc Tower in Isengard.',8.4,23689,19.335,'2026-04-14 09:08:31','nuTU5XcZTLA','/5VTN0pR8gcqV3EPUHHfMGnJYN9L.jpg'),(122,'The Lord of the Rings: The Return of the King','The Lord of the Rings: The Return of the King',2003,201,'New Zealand','en','Adventure, Fantasy, Action','Elijah Wood, Ian McKellen, Viggo Mortensen, Sean Astin, Andy Serkis','Peter Jackson','As armies mass for a final battle that will decide the fate of the world--and powerful, ancient forces of Light and Dark compete to determine the outcome--one member of the Fellowship of the Ring is revealed as the noble heir to the throne of the Kings of Men. Yet, the sole hope for triumph over evil lies with a brave hobbit, Frodo, who, accompanied by his loyal friend Sam and the hideous, wretched Gollum, ventures deep into the very dark heart of Mordor on his seemingly impossible quest to destroy the Ring of Power.​',8.5,26313,25.575,'2026-03-27 07:50:06','zckJCxYxn1g','/rCzpDGLbOoPwLjy3OAm5NUPOTrC.jpg'),(128,'Princess Mononoke','もののけ姫',1997,134,'Japan','ja','Adventure, Fantasy, Animation','Yoji Matsuda, Yuriko Ishida, Yuko Tanaka, Kaoru Kobayashi, Masahiko Nishimura','Hayao Miyazaki','Ashitaka, a prince of the disappearing Emishi people, is cursed by a demonized boar god and must journey to the west to find a cure. Along the way, he encounters San, a young human woman fighting to protect the forest, and Lady Eboshi, who is trying to destroy it. Ashitaka must find a way to bring balance to this conflict.',8.3,8893,15.217,'2026-04-14 09:08:48','I1dHzoRl0sQ','/cMYCDADoLKLbB83g4WnJegaZimC.jpg'),(129,'Spirited Away','千と千尋の神隠し',2001,125,'Japan','ja','Animation, Family, Fantasy','Rumi Hiiragi, Miyu Irino, Mari Natsuki, Takashi Naito, Yasuko Sawaguchi','Hayao Miyazaki','A young girl, Chihiro, becomes trapped in a strange new world of spirits. When her parents undergo a mysterious transformation, she must call upon the courage she never knew she had to free her family.',8.5,18152,27.748,'2026-03-28 06:46:22','GAp2_0JJskk','/39wmItIWsg5sZMyRUHLkWBcuVCM.jpg'),(141,'Donnie Darko','Donnie Darko',2001,114,'United States of America','en','Fantasy, Drama, Mystery','Jake Gyllenhaal, Jena Malone, James Duval, Drew Barrymore, Beth Grant','Richard Kelly','After narrowly escaping a bizarre accident, a troubled teenager is plagued by visions of a large bunny rabbit that manipulates him to commit a series of crimes.',7.8,13308,9.830,'2026-04-14 09:10:57','71RaE7JYTUU','/sv7D4vlfIH25lNjQYoXzoOFCYaz.jpg'),(149,'Akira','AKIRA',1988,124,'Japan','ja','Animation, Science Fiction, Action','Mitsuo Iwata, Nozomu Sasaki, Mami Koyama, Taro Ishida, Mizuho Suzuki','Katsuhiro Otomo','A secret military project endangers Neo-Tokyo when it turns a biker gang member into a rampaging psychic psychopath that only two teenagers and a group of psychics can stop.',7.9,4710,10.285,'2026-04-14 09:11:01','Jq4ER-P6NCQ','/neZ0ykEsPqxamsX6o5QNUFILQrz.jpg'),(155,'The Dark Knight','The Dark Knight',2008,152,'United Kingdom','en','Action, Crime, Thriller','Christian Bale, Heath Ledger, Aaron Eckhart, Michael Caine, Maggie Gyllenhaal','Christopher Nolan','Batman raises the stakes in his war on crime. With the help of Lt. Jim Gordon and District Attorney Harvey Dent, Batman sets out to dismantle the remaining criminal organizations that plague the streets. The partnership proves to be effective, but they soon find themselves prey to a reign of chaos unleashed by a rising criminal mastermind known to the terrified citizens of Gotham as the Joker.',8.5,35471,31.871,'2026-03-27 07:50:07','_PZpmTj1Q8Q','/qJ2tW6WMUDux911r6m7haRef0WH.jpg'),(185,'A Clockwork Orange','A Clockwork Orange',1971,137,'United Kingdom','en','Science Fiction, Crime','Malcolm McDowell, Patrick Magee, Carl Duering, Michael Bates, Warren Clarke','Stanley Kubrick','In a near-future Britain, young Alexander DeLarge and his pals get their kicks beating and raping anyone they please. When not destroying the lives of others, Alex swoons to the music of Beethoven. The state, eager to crack down on juvenile crime, gives an incarcerated Alex the option to undergo an invasive procedure that\'ll rob him of all personal agency. In a time when conscience is a commodity, can Alex change his tune?',8.2,13727,9.852,'2026-04-14 09:09:33','T54uZPI4Z8A','/